class ElasticsearchClient:
    """Base Elasticsearch client with connection management."""

    def __init__(self, hosts: list[str] = None, **kwargs):
        self.hosts = hosts or ["http://localhost:9200"]
        self.client = Elasticsearch(
            self.hosts,
            request_timeout=30,
            max_retries=3,
            retry_on_timeout=True,
            **kwargs
        )
        self._verify_connection()

    def _verify_connection(self):
        try:
            info = self.client.info()
            logger.info(
                f"Connected to Elasticsearch cluster: {info['cluster_name']}, "
                f"version: {info['version']['number']}"
            )
        except ConnectionError as e:
            logger.error(f"Failed to connect to Elasticsearch: {e}")
            raise

    def health_check(self) -> dict:
        return self.client.cluster.health()


class IndexManager:
    """Manages Elasticsearch index operations."""

    def __init__(self, es_client: ElasticsearchClient):
        self.client = es_client.client

    def create_index(self, index_name: str, mappings: dict = None, settings: dict = None) -> dict:
        if self.client.indices.exists(index=index_name):
            logger.warning(f"Index '{index_name}' already exists.")
            return {"acknowledged": True, "already_exists": True}

        body = {}
        if settings:
            body["settings"] = settings
        if mappings:
            body["mappings"] = mappings

        result = self.client.indices.create(index=index_name, body=body)
        logger.info(f"Index '{index_name}' created successfully.")
        return result

    def delete_index(self, index_name: str) -> dict:
        try:
            result = self.client.indices.delete(index=index_name)
            logger.info(f"Index '{index_name}' deleted successfully.")
            return result
        except NotFoundError:
            logger.warning(f"Index '{index_name}' not found.")
            return {"acknowledged": False, "not_found": True}

    def get_index_info(self, index_name: str) -> dict:
        try:
            return self.client.indices.get(index=index_name)
        except NotFoundError:
            logger.warning(f"Index '{index_name}' not found.")
            return {}

    def list_indices(self, pattern: str = "*") -> list:
        indices = self.client.cat.indices(index=pattern, format="json")
        return indices

    def update_mapping(self, index_name: str, properties: dict) -> dict:
        body = {"properties": properties}
        result = self.client.indices.put_mapping(index=index_name, body=body)
        logger.info(f"Mapping updated for index '{index_name}'.")
        return result


class DocumentManager:
    """Handles document CRUD operations and bulk indexing."""

    def __init__(self, es_client: ElasticsearchClient):
        self.client = es_client.client

    def index_document(self, index_name: str, document: dict,
                       doc_id: str = None, pipeline: str = None) -> dict:
        kwargs = {"index": index_name, "body": document}
        if doc_id:
            kwargs["id"] = doc_id
        if pipeline:
            kwargs["pipeline"] = pipeline

        result = self.client.index(**kwargs)
        logger.info(
            f"Document indexed in '{index_name}' with ID: {result['_id']}"
        )
        return result

    def get_document(self, index_name: str, doc_id: str) -> Optional[dict]:
        try:
            result = self.client.get(index=index_name, id=doc_id)
            return result["_source"]
        except NotFoundError:
            logger.warning(f"Document '{doc_id}' not found in '{index_name}'.")
            return None

    def update_document(self, index_name: str, doc_id: str, updates: dict) -> dict:
        body = {"doc": updates}
        result = self.client.update(index=index_name, id=doc_id, body=body)
        logger.info(f"Document '{doc_id}' updated in '{index_name}'.")
        return result

    def delete_document(self, index_name: str, doc_id: str) -> dict:
        try:
            result = self.client.delete(index=index_name, id=doc_id)
            logger.info(f"Document '{doc_id}' deleted from '{index_name}'.")
            return result
        except NotFoundError:
            logger.warning(f"Document '{doc_id}' not found in '{index_name}'.")
            return {"result": "not_found"}

    def bulk_index(self, index_name: str, documents: list[dict],
                   id_field: str = None) -> tuple[int, list]:
        actions = []
        for doc in documents:
            action = {
                "_index": index_name,
                "_source": doc
            }
            if id_field and id_field in doc:
                action["_id"] = doc[id_field]
            actions.append(action)

        success, errors = helpers.bulk(
            self.client, actions, raise_on_error=False, stats_only=False
        )
        logger.info(
            f"Bulk indexed {success} documents into '{index_name}'. "
            f"Errors: {len(errors)}"
        )
        return success, errors

    def bulk_index_from_generator(self, index_name: str, generator, chunk_size: int = 500):
        def action_generator():
            for doc in generator:
                yield {
                    "_index": index_name,
                    "_source": doc
                }

        success, errors = helpers.bulk(
            self.client, action_generator(),
            chunk_size=chunk_size, raise_on_error=False, stats_only=False
        )
        logger.info(f"Bulk indexed {success} documents. Errors: {len(errors)}")
        return success, errors


class SearchEngine:
    """Full-text search functionality with various query types."""

    def __init__(self, es_client: ElasticsearchClient):
        self.client = es_client.client

    def simple_search(self, index_name: str, query_string: str,
                      fields: list[str] = None, size: int = 10,
                      from_: int = 0) -> dict:
        fields = fields or ["*"]
        body = {
            "query": {
                "multi_match": {
                    "query": query_string,
                    "fields": fields,
                    "type": "best_fields",
                    "fuzziness": "AUTO"
                }
            },
            "size": size,
            "from": from_,
            "highlight": {
                "fields": {field: {} for field in fields}
            }
        }
        return self._execute_search(index_name, body)

    def advanced_search(self, index_name: str, must: list = None,
                        should: list = None, must_not: list = None,
                        filter_: list = None, size: int = 10,
                        from_: int = 0, sort: list = None) -> dict:
        bool_query = {}
        if must:
            bool_query["must"] = must
        if should:
            bool_query["should"] = should
        if must_not:
            bool_query["must_not"] = must_not
        if filter_:
            bool_query["filter"] = filter_

        body = {
            "query": {"bool": bool_query},
            "size": size,
            "from": from_
        }
        if sort:
            body["sort"] = sort

        return self._execute_search(index_name, body)

    def phrase_search(self, index_name: str, field: str, phrase: str,
                      slop: int = 0, size: int = 10) -> dict:
        body = {
            "query": {
                "match_phrase": {
                    field: {
                        "query": phrase,
                        "slop": slop
                    }
                }
            },
            "size": size
        }
        return self._execute_search(index_name, body)

    def wildcard_search(self, index_name: str, field: str,
                        pattern: str, size: int = 10) -> dict:
        body = {
            "query": {
                "wildcard": {
                    field: {"value": pattern}
                }
            },
            "size": size
        }
        return self._execute_search(index_name, body)

    def range_search(self, index_name: str, field: str,
                     gte=None, lte=None, gt=None, lt=None,
                     size: int = 10) -> dict:
        range_params = {}
        if gte is not None:
            range_params["gte"] = gte
        if lte is not None:
            range_params["lte"] = lte
        if gt is not None:
            range_params["gt"] = gt
        if lt is not None:
            range_params["lt"] = lt

        body = {
            "query": {
                "range": {
                    field: range_params
                }
            },
            "size": size
        }
        return self._execute_search(index_name, body)

    def aggregation_search(self, index_name: str, query: dict = None,
                           aggregations: dict = None, size: int = 0) -> dict:
        body = {"size": size}
        if query:
            body["query"] = query
        if aggregations:
            body["aggs"] = aggregations

        return self._execute_search(index_name, body)

    def search_with_scroll(self, index_name: str, query: dict,
                           scroll: str = "5m", size: int = 1000):
        body = {"query": query, "size": size}
        result = self.client.search(index=index_name, body=body, scroll=scroll)
        scroll_id = result["_scroll_id"]
        hits = result["hits"]["hits"]

        while hits:
            for hit in hits:
                yield hit
            result = self.client.scroll(scroll_id=scroll_id, scroll=scroll)
            scroll_id = result["_scroll_id"]
            hits = result["hits"]["hits"]

        self.client.clear_scroll(scroll_id=scroll_id)

    def _execute_search(self, index_name: str, body: dict) -> dict:
        result = self.client.search(index=index_name, body=body)
        total = result["hits"]["total"]["value"]
        logger.info(f"Search in '{index_name}' returned {total} results.")
        return {
            "total": total,
            "hits": [
                {
                    "id": hit["_id"],
                    "score": hit["_score"],
                    "source": hit["_source"],
                    "highlight": hit.get("highlight", {})
                }
                for hit in result["hits"]["hits"]
            ],
            "aggregations": result.get("aggregations", {}),
            "took": result["took"]
        }


