class ElasticsearchLogHandler(logging.Handler):
    """Python logging handler that sends logs to Elasticsearch."""

    def __init__(self, log_manager: LogManager, buffer_size: int = 100):
        super().__init__()
        self.log_manager = log_manager
        self.buffer_size = buffer_size
        self._buffer = []

    def emit(self, record: logging.LogRecord):
        try:
            log_entry = {
                "timestamp": datetime.utcfromtimestamp(record.created).isoformat(),
                "level": record.levelname,
                "logger_name": record.name,
                "message": self.format(record),
                "source": f"{record.pathname}:{record.lineno}",
                "metadata": {
                    "function": record.funcName,
                    "module": record.module,
                    "process_id": record.process,
                    "thread_id": record.thread
                }
            }
            if record.exc_info and record.exc_info[0] is not None:
                log_entry["stack_trace"] = self.formatException(record.exc_info)

            self._buffer.append(log_entry)

            if len(self._buffer) >= self.buffer_size:
                self.flush()

        except Exception:
            self.handleError(record)

    def flush(self):
        if self._buffer:
            try:
                self.log_manager.bulk_log(self._buffer.copy())
                self._buffer.clear()
            except Exception as e:
                logger.error(f"Failed to flush logs to Elasticsearch: {e}")

    def close(self):
        self.flush()
        super().close()


class SearchPlatform:
    """Main entry point for the centralized logging and search platform."""

    def __init__(self, hosts: list[str] = None, service_name: str = "default",
                 environment: str = "development"):
        self.es_client = ElasticsearchClient(hosts=hosts)
        self.index_manager = IndexManager(self.es_client)
        self.doc_manager = DocumentManager(self.es_client)
        self.search_engine = SearchEngine(self.es_client)
        self.log_manager = LogManager(
            self.es_client,
            service_name=service_name,
            environment=environment
        )

    def setup_python_logging(self, logger_name: str = None,
                             buffer_size: int = 100) -> logging.Logger:
        target_logger = logging.getLogger(logger_name)
        handler = ElasticsearchLogHandler(self.log_manager, buffer_size=buffer_size)
        handler.setFormatter(
            logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
        )
        target_logger.addHandler(handler)
        return target_logger

    def create_content_index(self, index_name: str,
                             custom_mappings: dict = None) -> dict:
        default_mappings = {
            "properties": {
                "title": {
                    "type": "text",
                    "analyzer": "standard",
                    "fields": {
                        "keyword": {"type": "keyword"},
                        "suggest": {"type": "completion"}
                    }
                },
                "content": {
                    "type": "text",
                    "analyzer": "standard"
                },
                "tags": {"type": "keyword"},
                "category": {"type": "keyword"},
                "author": {"type": "keyword"},
                "created_at": {"type": "date"},
                "updated_at": {"type": "date"},
                "metadata": {"type": "object", "dynamic": True}
            }
        }

        mappings = custom_mappings or default_mappings
        settings = {
            "number_of_shards": 2,
            "number_of_replicas": 1,
            "analysis": {
                "analyzer": {
                    "custom_analyzer": {
                        "type": "custom",
                        "tokenizer": "standard",
                        "filter": ["lowercase", "stop", "snowball"]
                    }
                }
            }
        }

        return self.index_manager.create_index(index_name, mappings, settings)

    def health(self) -> dict:
        cluster_health = self.es_client.health_check()
        indices = self.index_manager.list_indices()
        return {
            "cluster": cluster_health,
            "indices_count": len(indices),
            "indices": indices
        }


